chart.config_raw:
const ctx = document.getElementById('maeChart').getContext('2d');
new Chart(ctx, {
  type: 'bar',
  data: {
    labels: ['FLOPs\n(shared int.)', 'FLOPs', 'Size &\nTokens', 'PCA+FLOPs\n(d=2)', 'Sloth basic\n(d=2)', 'Sloth\n(d=2)'],
    datasets: [{
      label: 'Average MAE (pp)',
      data: [4.9, 3.8, 4.1, 5.4, 3.6, 2.9],
      backgroundColor: [
        '#718096','#718096','#718096','#718096','#4dabf7','#4dabf7'
      ],
      borderRadius: 6,
      barPercentage: 0.7
    }]
  },
  options: {
    animation: false,
    maintainAspectRatio: false,
    indexAxis: 'x',
    scales: {
      y: {
        beginAtZero: true,
        max: 7,
        grid: { color: '#e2e8f0' },
        ticks: {
          color: '#4a5568',
          callback: function(v) { return v + ' pp'; }
        }
      },
      x: {
        grid: { display: false },
        ticks: {
          color: '#4a5568',
          font: { size: 11 },
          maxRotation: 0
        }
      }
    },
    plugins: {
      legend: { display: false },
      tooltip: {
        callbacks: {
          label: function(c) { return c.parsed.y + ' pp MAE'; }
        }
      }
    }
  }
});
